competitors.source:
(() => {
    interface SmallObj {
      a: string;
    }
    interface LargeObj {
      a: string;
      b: number;
    }
    return {build: () => createValidate<SmallObj | LargeObj>(), buildErrors: () => noErrs(createGetValidationErrors<SmallObj | LargeObj>())};
  })()

c(
    Type.Union([Type.Object({a: Type.String()}), Type.Object({a: Type.String(), b: Type.Number()})])
  )

c({
      anyOf: [
        {type: 'object', properties: {a: {type: 'string'}}, required: ['a']},
        {type: 'object', properties: {a: {type: 'string'}, b: {type: 'number'}}, required: ['a', 'b']},
      ],
    })
